from dataclasses import dataclass, field
from typing import Callable, Any

@dataclass
class Action:
    name: str
    handler: Callable[[dict], None]  # takes context dict

@dataclass
class Transition:
    event: str
    source: str
    target: str
    guard: Callable[[dict], bool] | None = None  # condition to allow transition
    actions: list[Action] = field(default_factory=list)

@dataclass
class State:
    name: str
    on_enter: Callable[[dict], None] | None = None
    on_exit: Callable[[dict], None] | None = None

